# Initialize logging
logging_client = cloud_logging.Client()
logger = logging_client.logger('pubsub-processor')

# Secret key for HMAC verification (should be stored in Secret Manager in production)
SECRET_KEY = os.environ.get('MESSAGE_SIGNATURE_KEY', '').encode()

def verify_message_signature(data: bytes, signature: str) -> bool:
    """Verify HMAC signature of the message data."""
    if not SECRET_KEY:
        logger.log_text("WARNING: No signature key configured", severity='WARNING')
        return False
    
    expected_signature = hmac.new(SECRET_KEY, data, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def deserialize_safe_json(data: bytes) -> dict:
    """Safely deserialize JSON data instead of pickle."""
    try:
        return json.loads(data.decode('utf-8'))
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        logger.log_text(f"Failed to deserialize JSON: {str(e)}", severity='ERROR')
        raise ValueError(f"Invalid JSON data: {str(e)}")

def process_batch_job(job_data: dict) -> dict:
    """Process a batch job with validated data."""
    job_id = job_data.get('job_id')
    job_type = job_data.get('job_type')
    parameters = job_data.get('parameters', {})
    
    # Validate job data structure
